-- Urdu Portal (243 entries)
DECLARE
    PROCEDURE et(p_code VARCHAR2, p_locale VARCHAR2, p_value VARCHAR2) IS
        v_tk_id NUMBER; v_exists NUMBER;
    BEGIN
        BEGIN SELECT id INTO v_tk_id FROM translation_key WHERE code = p_code; EXCEPTION WHEN NO_DATA_FOUND THEN RETURN; END;
        SELECT COUNT(*) INTO v_exists FROM translation WHERE translation_key_id = v_tk_id AND locale = p_locale;
        IF v_exists = 0 THEN INSERT INTO translation (id, translation_key_id, locale, value) VALUES (translation_seq.NEXTVAL, v_tk_id, p_locale, p_value); END IF;
    END;
BEGIN
